struct timespec time_sub(struct timespec a, struct timespec b)
{
  struct timespec ret;
  int64_t nsec_diff;

  if (a.tv_nsec < b.tv_nsec) {
    nsec_diff = (int64_t)a.tv_nsec - (int64_t)b.tv_nsec + 1000000000;
    ret.tv_sec = a.tv_sec - b.tv_sec - 1;
  } else {
    nsec_diff = (int64_t)a.tv_nsec - (int64_t)b.tv_nsec;
    ret.tv_sec = a.tv_sec - b.tv_sec;
  }

  /* Ensure tv_nsec is within valid range [0, 999999999] */
  if (nsec_diff < 0) {
    ret.tv_nsec = 0;
  } else if (nsec_diff >= 1000000000) {
    ret.tv_nsec = 999999999;
  } else {
    ret.tv_nsec = nsec_diff;
  }

  return ret;
}
